#!/bin/bash
# Final clean run — all bug fixes applied, all scripts smoke-verified.
# Each track writes to its own out/ dir; metrics.json includes _meta
# (seed, git commit, torch version, GPU name) for full reproducibility.
#
# Run ONCE in background.
# CRITICAL: do not edit this file while running.
set -uo pipefail
SCRIPT_DIR="$(realpath "$(dirname "${BASH_SOURCE[0]}")")"
PAPER_DIR="$(dirname "$SCRIPT_DIR")"
cd "$PAPER_DIR"
LOGDIR="$PAPER_DIR/logs/final"
mkdir -p "$LOGDIR"

GIT_COMMIT=$(git rev-parse --short HEAD)
echo "[$(date +%T)] === Final clean run starting (commit $GIT_COMMIT) ===" \
    | tee -a "$LOGDIR/00_runner.log"

log() {
    echo "[$(date +%T)] $*" | tee -a "$LOGDIR/00_runner.log"
}

run_track() {
    local name="$1"; shift
    local logfile="$1"; shift
    log "=== $name ==="
    local start=$(date +%s)
    "$@" > "$LOGDIR/$logfile" 2>&1
    local rc=$?
    local elapsed=$(($(date +%s) - start))
    if [ $rc -ne 0 ]; then
        log "    !! $name FAILED rc=$rc  ${elapsed}s — see $LOGDIR/$logfile"
    else
        log "    $name OK in ${elapsed}s"
    fi
}

# ---- Wave 1: cross-architecture C1/C2 ----
# Track 1 SD C1/C2 already done (sd_c1_c2 + sd_c1_c2_n64); skip
# Track 3 sample scaling re-run all 3 domains for clean _meta
run_track "T3 scaling bedroom" "track3_bedroom.log" \
    python3 -u experiments/metrics/run_sample_scaling.py \
        --domain bedroom --n-max 128 --Ns 8 16 32 64 128 --seed 2027

run_track "T3 scaling ffhq" "track3_ffhq.log" \
    python3 -u experiments/metrics/run_sample_scaling.py \
        --domain ffhq --n-max 128 --Ns 8 16 32 64 128 --seed 2027

run_track "T3 scaling church" "track3_church.log" \
    python3 -u experiments/metrics/run_sample_scaling.py \
        --domain church --n-max 128 --Ns 8 16 32 64 128 --seed 2027

# ---- Wave 2: extended baselines & ablations ----
run_track "T4 FFHQ encoder train" "track4_train.log" \
    python3 -u experiments/domains/ffhq/encoder/train.py \
        --num-iters 80000 --batch 1 \
        --ckpt-iters 1000 5000 10000 20000 40000 60000 80000 \
        --seed 2027

run_track "T4 FFHQ encoder eval" "track4_eval.log" \
    python3 -u experiments/domains/ffhq/encoder/eval_c5.py \
        --ckpts experiments/out/ffhq_c5/ckpt/enc_001000.pt \
                experiments/out/ffhq_c5/ckpt/enc_005000.pt \
                experiments/out/ffhq_c5/ckpt/enc_010000.pt \
                experiments/out/ffhq_c5/ckpt/enc_020000.pt \
                experiments/out/ffhq_c5/ckpt/enc_040000.pt \
                experiments/out/ffhq_c5/ckpt/enc_060000.pt \
                experiments/out/ffhq_c5/ckpt/enc_080000.pt \
        --num-test 32

run_track "T5 LatentCLR" "track5_latentclr.log" \
    python3 -u experiments/baselines/latentclr/train.py \
        --K 20 --B 2 --chunk 1 --epochs 50 --iters-per-epoch 500 \
        --lod 2 --seed 2027

run_track "T5 DisCo" "track5_disco.log" \
    python3 -u experiments/baselines/disco/train.py \
        --K 20 --B 2 --chunk 1 --epochs 50 --iters-per-epoch 500 \
        --lod 2 --seed 2027

run_track "T6 DAAM SD" "track6_daam.log" \
    python3 -u experiments/diffusion/run_daam_comparison.py \
        --n-seeds 32 --seed 2027

run_track "T7 Park-NeurIPS23 repro" "track7_park.log" \
    python3 -u experiments/diffusion/run_park_repro.py \
        --n-seeds 8 --K-probes 32 --top-k 4 --seed 2027

run_track "T8 FFHQ truncation-ψ" "track8_truncation.log" \
    python3 -u experiments/domains/ffhq/run_truncation_ablation.py \
        --num-samples 64 --seed 2027

run_track "T9 multi-CLIP C2" "track9_multi_clip.log" \
    python3 -u experiments/metrics/run_multi_clip_c2.py \
        --num-samples 16 --seed 2027

run_track "T10 per-layer bedroom" "track10_per_layer_bedroom.log" \
    python3 -u experiments/metrics/run_per_layer_c1.py \
        --domain bedroom --n-samples 32 --seed 2027

run_track "T10 per-layer ffhq" "track10_per_layer_ffhq.log" \
    python3 -u experiments/metrics/run_per_layer_c1.py \
        --domain ffhq --n-samples 32 --seed 2027

run_track "T11 walltime" "track11_walltime.log" \
    python3 -u experiments/method/run_walltime_benchmark.py \
        --domain bedroom --seed 2027

run_track "T12 C6 N-scaling" "track12_c6_scaling.log" \
    python3 -u experiments/metrics/run_c6_scaling.py \
        --Ns 128 192 256 384 512 768 --seed 2027

run_track "T13 FFHQ resolution invariance" "track13_resolution.log" \
    python3 -u experiments/domains/ffhq/run_resolution_invariance.py \
        --num-samples 32 --seed 2027

# ---- Wave 3 ----
run_track "T14 noise bedroom" "track14_noise_bedroom.log" \
    python3 -u experiments/metrics/run_noise_robustness.py \
        --domain bedroom --num-samples 64 --seed 2027

run_track "T14 noise ffhq" "track14_noise_ffhq.log" \
    python3 -u experiments/metrics/run_noise_robustness.py \
        --domain ffhq --num-samples 64 --seed 2027

run_track "T17 intrinsic bedroom" "track17_intrinsic_bedroom.log" \
    python3 -u experiments/method/run_intrinsic_dim.py \
        --domain bedroom --n-latents 32 --K-probes 128 --seed 2027

run_track "T17 intrinsic ffhq" "track17_intrinsic_ffhq.log" \
    python3 -u experiments/method/run_intrinsic_dim.py \
        --domain ffhq --n-latents 32 --K-probes 128 --seed 2027

run_track "T18 FD validation" "track18_fd_validation.log" \
    python3 -u experiments/method/run_fd_validation.py \
        --domain bedroom --n-pairs 16 --seed 2027

# ---- Wave 4 ----
run_track "T19 DINOv2 path curvature" "track19_dino.log" \
    python3 -u experiments/metrics/run_dino_path_curvature.py \
        --num-samples 16 --seed 2027

run_track "T20 FFHQ alpha-magnitude scan" "track20_alpha_scan.log" \
    python3 -u experiments/domains/ffhq/run_alpha_magnitude_scan.py \
        --n-samples 32 --seed 2027

# ---- Track 2 last (depends on Track 5 LatentCLR + DisCo directions) ----
run_track "T2 editing head-to-head" "track2_editing.log" \
    python3 -u experiments/baselines/run_editing_head_to_head.py \
        --n-test 1000 --n-curv-samples 64 --k-top 16 --seed 2027

log "=== ALL FINAL TRACKS COMPLETE ==="
